// User Management
package role

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40010/idl"
)

const ERR_INVALID_VALUE int32 = 1 // Invalid arguments

// Role management interface
type Role interface {
	idl.Object

	// Retrieve role information.
	//
	//	@return role info
	GetInfo(ctx context.Context) (Info, error)

	// Change role settings.
	//
	//	@param info  New role information
	//
	//	@return 0 if OK
	//	@return 1 if the role information is invalid
	UpdateFull(ctx context.Context, info Info) (int32, error)
}

// A granted privilege
type Privilege struct {
	Name string   // Privilege name
	Args []string // Privilege arguments
}

// Role information
type Info struct {
	Description string      // Free-form description
	Locked      bool        // true if the role cannot be deleted
	Privileges  []Privilege // List of privileges for this role
}
